#include <iostream>
#include <string>

class Point {
public:
    int x, y;

    Point(int x_coord = 0, int y_coord = 0) : x(x_coord), y(y_coord) {}
};

bool operator==(const Point& p1, const Point& p2) {
    return (p1.x == p2.x && p1.y == p2.y);
}

std::string bool_to_string(bool b) {
    return b ? "true" : "false";
}

int main() {
    // The actual test cases will be inserted here by the system.
    Point p1(1, 1); Point p2(1, 1); std::cout << bool_to_string(p1 == p2) << std::endl;
    Point p3(1, 2); Point p4(1, 1); std::cout << bool_to_string(p3 == p4) << std::endl;
    Point p5(2, 1); Point p6(1, 1); std::cout << bool_to_string(p5 == p6) << std::endl;
    Point p7(0, 0); Point p8(0, 0); std::cout << bool_to_string(p7 == p8) << std::endl;
    Point p9(-5, -10); Point p10(-5, -10); std::cout << bool_to_string(p9 == p10) << std::endl;
    Point p11(-5, -10); Point p12(1, 2); std::cout << bool_to_string(p11 == p12) << std::endl;
    Point p13(100, 200); Point p14(100, 200); std::cout << bool_to_string(p13 == p14) << std::endl;
    Point p15(100, 200); Point p16(200, 100); std::cout << bool_to_string(p15 == p16) << std::endl;
    Point p17(1, 1); Point p18(1, 1); std::cout << bool_to_string(p18 == p17) << std::endl;
    return 0;
}
